    while (T--) {
        char T_str[102], S_str[100005];
        scanf("%s %s", T_str, S_str);
        int S_len = strlen(S_str);
        for (int i = 0; i < S_len; i++) {
            int found = 0;
            for (int j = i; j < S_len; j++) {
                char substr[j - i + 1 + 1];
                strncpy(substr, S_str + i, j - i + 1);
                substr[j - i + 1] = '\0';
                if (match(substr, T_str)) {
                    printf("%d ", j + 1);
                    found = 1;
                    break;
                }
            }
            if (!found) printf("-1 ");
        }
        printf("\n");
    }
    return 0;
}

int match(char *S, char *T) {
    int S_len = strlen(S), T_len = strlen(T);
    int i = 0, j = 0;
    while (i < S_len && j < T_len) {
        if (T[j] == '*') {
            j++;
            if (j == T_len) return 1;
            while (i < S_len && S[i] != T[j]) i++;
        } else if (S[i] == T[j]) {
            i++, j++;
        } else {
            return 0;
        }
    }
    return i == S_len && (j == T_len || (j < T_len && T[j] == '*'));
}

