#include <iostream>
#include <string>
using namespace std;

bool match(string S, string T) {
    int i = 0, j = 0;
    while (i < S.size() && j < T.size()) {
        if (T[j] == '*') {
            j++;
            if (j == T.size()) return true;
            while (i < S.size() && S[i] != T[j]) i++;
        } else if (S[i] == T[j]) {
            i++, j++;
        } else {
            return false;
        }
    }
    return i == S.size() && (j == T.size() || (j < T.size() && T[j] == '*'));
}

