import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String T_str = sc.nextLine();
            String S_str = sc.nextLine();
            int S_len = S_str.length();
            for (int i = 0; i < S_len; i++) {
                int found = 0;
                for (int j = i; j < S_len; j++) {
                    String substr = S_str.substring(i, j + 1);
                    if (match(substr, T_str)) {
                        System.out.print(j + 1 + " ");
                        found = 1;
                        break;
                    }
                }
                if (found == 0) System.out.print(-1 + " ");
            }
            System.out.println();
        }
    }

    public static boolean match(String S, String T) {
        int i = 0, j = 0;
        while (i < S.length() && j < T.length()) {
            if (T.charAt(j) == '*') {
                j++;
                if (j == T.length()) return true;
                while (i < S.length() && S.charAt(i) != T.charAt(j)) i++;
            } else if (S.charAt(i) == T.charAt(j)) {
                i++;
                j++;
            } else {
                return false;
            }
        }
        return i == S.length() && (j == T.length() || (j < T.length() && T.charAt(j) == '*'));
    }
}

